mapper.select:
select *
from nx_department_dis_goods as ddg
left join nx_distributer_goods as dg on dg.nx_distributer_goods_id = ddg.nx_DDG_dis_goods_id
left join nx_distributer_standard as ds on ds.nx_DS_dis_goods_id = dg.nx_distributer_goods_id
left join nx_distributer_alias as da on da.nx_DA_dis_goods_id = dg.nx_distributer_goods_id


        and ddg.nx_DDG_department_id = #{depId}


        and ddg.nx_DDG_department_father_id = #{depFatherId}


        and ddg.nx_DDG_dis_goods_father_id = #{fatherId}


order by dg.nx_dg_goods_py

    limit #{offset}, #{limit}

select *
from nx_department_dis_goods
where nx_DDG_department_father_id = #{depFatherId}
  and nx_DDG_dis_goods_id = #{disGoodsId}

select count(*)
from nx_department_dis_goods
where nx_DDG_department_father_id = #{depFatherId}
  and nx_DDG_dis_goods_father_id = #{fatherId}

select *
from nx_department_dis_goods
where nx_department_dis_goods_id = #{value}

select * from nx_department_dis_goods


        and nx_DDG_department_id = #{depId}


        and nx_DDG_order_goods_name = #{name}


        and nx_DDG_gb_department_id = #{gbDepId}


        and nx_DDG_department_father_id = #{depFatherId}


        and nx_DDG_dis_goods_id = #{disGoodsId}


        and nx_DDG_dis_goods_father_id = #{disGoodsFatherId}

select *, great.nx_distributer_father_goods_id 'g_nx_distributer_father_goods_id', great.nx_dfg_fathers_father_id 'g_nx_dfg_fathers_father_id', great.nx_dfg_father_goods_name 'g_nx_dfg_father_goods_name', great.nx_dfg_father_goods_img 'g_nx_dfg_father_goods_img', dfg.nx_distributer_father_goods_id 'f_nx_distributer_father_goods_id', dfg.nx_dfg_fathers_father_id 'f_nx_dfg_fathers_father_id', dfg.nx_dfg_father_goods_name 'f_nx_dfg_father_goods_name' from nx_department_dis_goods as ddg left join nx_distributer_goods as dg on dg.nx_distributer_goods_id = ddg.nx_DDG_dis_goods_id left join nx_distributer_alias as da on da.nx_DA_dis_goods_id = ddg.nx_DDG_dis_goods_id left join nx_distributer_standard as ds on ds.nx_DS_dis_goods_id = dg.nx_distributer_goods_id left join nx_distributer_father_goods as dfg on dfg.nx_distributer_father_goods_id = ddg.nx_DDG_dis_goods_grand_id left join nx_distributer_father_goods as great on great.nx_distributer_father_goods_id = dfg.nx_dfg_fathers_father_id left join nx_department_order_history as dor on dor.nx_DO_dis_goods_id = ddg.nx_DDG_dis_goods_id and dor.nx_DO_status < #{status} and dor.nx_DO_department_id = #{depId}
and ddg.nx_DDG_department_id = #{depId}
order by great.nx_dfg_father_goods_sort, dfg.nx_dfg_father_goods_sort, dg.nx_dg_goods_sons_sort

select * from nx_department_dis_goods as nddg left join nx_department as nd on nd.nx_department_id = nddg.nx_DDG_department_id left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id = nddg.nx_DDG_dis_goods_grand_id left join nx_distributer_father_goods as great on great.nx_distributer_father_goods_id = ndfg.nx_dfg_fathers_father_id left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = nddg.nx_DDG_dis_goods_id
and nddg.nx_DDG_department_father_id = #{depFatherId}
and nddg.nx_DDG_gb_department_father_id = #{gbDepFatherId}
order by great.nx_dfg_father_goods_sort, ndfg.nx_dfg_father_goods_sort, ndg.nx_dg_goods_sons_sort

select * from nx_department_dis_goods


        and nx_DDG_dis_goods_id = #{disGoodsId}


        and nx_DDG_gb_department_id = #{gbDepId}


        and nx_DDG_department_id = #{depId}


        and nx_DDG_order_goods_name = #{name}


        and nx_DDG_order_standard = #{standard}

select * from nx_department_dis_goods as nddg
left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id =
nddg.nx_DDG_dis_goods_grand_id
left join gb_department as gd on gd.gb_department_id = nddg.nx_DDG_gb_department_id


        and nx_DDG_nx_distributer_id = #{nxDisId}


        and nx_DDG_gb_distributer_id = #{gbDisId}

select nx_department_dis_goods_id from nx_department_dis_goods as ddg left join nx_distributer_goods as dg on dg.nx_distributer_goods_id = ddg.nx_DDG_dis_goods_id left join nx_distributer_father_goods as f on f.nx_distributer_father_goods_id = dg.nx_dg_dfg_goods_father_id left join nx_distributer_father_goods as g on g.nx_distributer_father_goods_id = f.nx_dfg_fathers_father_id left join nx_distributer_father_goods as gg on gg.nx_distributer_father_goods_id = g.nx_dfg_fathers_father_id
AND ddg.nx_DDG_department_id = #{depId}
AND dg.nx_dg_pull_off = #{pull}
AND dg.nx_dg_goods_is_hidden = #{isHidden}
AND dg.nx_dg_dfg_goods_father_id IS NOT NULL
AND dg.nx_dg_dfg_goods_father_id IS NULL
ORDER BY gg.nx_dfg_father_goods_sort, g.nx_dfg_father_goods_sort, f.nx_dfg_father_goods_sort, dg.nx_dg_goods_sort,dg.nx_dg_goods_sons_sort

select * from nx_department_dis_goods


        and nx_DDG_dis_goods_id = #{disGoodsId}


        and nx_DDG_gb_department_id = #{gbDepId}


        and nx_DDG_department_id = #{depId}


        and nx_DDG_order_goods_name = #{name}


        and nx_DDG_order_standard = #{standard}
